/**
 * Transcript parsing — client inference, dispatch, and format-specific parsers.
 * Port of scripts/_transcript_parse.py
 */

import { readFileSync, statSync } from 'node:fs'
import { basename, extname } from 'node:path'

import type { Client, ParsedTranscript, TranscriptMessage, TranscriptToolEvent } from '../types/transcript.js'
import { toPosixPath } from '../utils/path.js'
import {
  SKIP_BLOCK_TYPES,
  TEXT_BLOCK_TYPES,
  TOOL_RESULT_TYPES,
  TOOL_USE_TYPES,
  deduplicateMessages,
  deduplicateToolEvents,
  earliestTimestamp,
  ensureDict,
  ensureList,
  extractGeminiText,
  extractTextBlocks,
  findFirstMappingWithKeys,
  getNested,
  joinParagraphs,
  loadJsonl,
  normalizeTimestamp,
  summarizeValue,
} from './common.js'

// ---------------------------------------------------------------------------
// Client inference + dispatch
// ---------------------------------------------------------------------------

export function inferClient(client: string, sourcePath: string): Client {
  if (client !== 'auto') {
    return client as Client
  }
  const normalized = toPosixPath(sourcePath).toLowerCase()
  const fileName = basename(sourcePath).toLowerCase()
  if (normalized.includes('/.codex/') || fileName.startsWith('rollout-')) {
    return 'codex'
  }
  if (normalized.includes('/.claude/') || normalized.includes('/projects/')) {
    return 'claude'
  }
  if (normalized.includes('/.gemini/') || normalized.includes('checkpoint')) {
    return 'gemini'
  }
  throw new Error(`could not infer transcript client from source path: ${sourcePath}`)
}

export function parseTranscript(client: string, sourcePath: string): ParsedTranscript {
  const resolved = inferClient(client, sourcePath)
  if (resolved === 'codex') {
    return parseCodexTranscript(sourcePath)
  }
  if (resolved === 'claude') {
    return parseClaudeTranscript(sourcePath)
  }
  if (resolved === 'gemini') {
    return parseGeminiTranscript(sourcePath)
  }
  throw new Error(`unsupported transcript client: ${resolved}`)
}

// ---------------------------------------------------------------------------
// Codex parser
// ---------------------------------------------------------------------------

export function parseCodexTranscript(filePath: string): ParsedTranscript {
  const records = loadJsonl(filePath)
  const stem = basename(filePath, extname(filePath))
  let sessionId = stem
  let title = stem
  let startedAt = normalizeTimestamp(statSync(filePath).mtimeMs / 1000)
  let cwd = ''
  let branch = ''
  const messages: TranscriptMessage[] = []
  const toolEvents: TranscriptToolEvent[] = []

  for (const record of records) {
    const recordType = String(record['type'] ?? '')
    const timestamp = normalizeTimestamp(record['timestamp'], startedAt)

    if (recordType === 'session_meta') {
      const payload = ensureDict(record['payload'])
      sessionId = String(payload['id'] ?? '') || sessionId
      title = String(payload['thread_name'] ?? '') || String(payload['title'] ?? '') || title
      startedAt = earliestTimestamp(startedAt, payload['timestamp'])
      cwd = String(payload['cwd'] ?? '') || cwd
      branch = String(getNested(payload, 'git', 'branch') ?? '') || branch
      continue
    }

    if (recordType !== 'response_item' && recordType !== 'event_msg') {
      continue
    }

    const payload = ensureDict(record['payload'])
    const payloadType = String(payload['type'] ?? '')

    if (payloadType === 'message') {
      const role = String(payload['role'] ?? '').toLowerCase()
      if (role === 'user' || role === 'assistant') {
        const text = extractTextBlocks(payload['content'])
        if (text) {
          messages.push({ role, text, timestamp })
        }
      }
      continue
    }

    if (payloadType === 'user_message' || payloadType === 'agent_message') {
      const role = payloadType === 'user_message' ? 'user' : 'assistant'
      const text = String(payload['message'] ?? '').trim()
      if (text) {
        messages.push({ role, text, timestamp })
      }
      continue
    }

    if (payloadType === 'function_call') {
      const name = String(payload['name'] ?? '') || 'function_call'
      const args = payload['arguments'] ?? payload['input']
      toolEvents.push({
        summary: `${name} input=${summarizeValue(args)}`,
        timestamp,
      })
      continue
    }

    if (payloadType === 'custom_tool_call') {
      const name = String(payload['name'] ?? '') || String(payload['call_id'] ?? '') || 'custom_tool_call'
      toolEvents.push({
        summary: `${name} input=${summarizeValue(payload['input'])}`,
        timestamp,
      })
      continue
    }

    if (payloadType === 'function_call_output') {
      const name = String(payload['name'] ?? '') || String(payload['call_id'] ?? '') || 'function_call_output'
      const output = payload['output'] ?? payload['content']
      toolEvents.push({
        summary: `${name} output=${summarizeValue(output)}`,
        timestamp,
      })
      continue
    }

    if (payloadType === 'custom_tool_call_output') {
      const name = String(payload['name'] ?? '') || String(payload['call_id'] ?? '') || 'custom_tool_call_output'
      const output = payload['output'] ?? payload['content']
      toolEvents.push({
        summary: `${name} output=${summarizeValue(output)}`,
        timestamp,
      })
    }
  }

  return {
    client: 'codex',
    session_id: sessionId,
    title,
    started_at: startedAt,
    cwd,
    branch,
    messages: deduplicateMessages(messages),
    tool_events: deduplicateToolEvents(toolEvents),
    source_path: filePath,
  }
}

// ---------------------------------------------------------------------------
// Claude parser
// ---------------------------------------------------------------------------

export function parseClaudeTranscript(filePath: string): ParsedTranscript {
  const records = loadJsonl(filePath)
  const stem = basename(filePath, extname(filePath))
  let sessionId = stem
  const title = stem
  let startedAt = normalizeTimestamp(statSync(filePath).mtimeMs / 1000)
  let cwd = ''
  let branch = ''
  const messages: TranscriptMessage[] = []
  const toolEvents: TranscriptToolEvent[] = []

  for (const record of records) {
    const recordType = String(record['type'] ?? '')
    const timestamp = normalizeTimestamp(record['timestamp'], startedAt)
    sessionId = String(record['sessionId'] ?? '') || sessionId
    startedAt = earliestTimestamp(startedAt, record['timestamp'])
    cwd = String(record['cwd'] ?? '') || cwd
    branch = String(record['gitBranch'] ?? '') || branch

    if (recordType !== 'user' && recordType !== 'assistant') {
      continue
    }

    const message = ensureDict(record['message'])
    const role = String(message['role'] ?? '').toLowerCase() || recordType
    const textParts: string[] = []
    const content = message['content']

    if (typeof content === 'string') {
      const text = content.trim()
      if ((role === 'user' || role === 'assistant') && text) {
        messages.push({ role, text, timestamp })
      }
      continue
    }

    for (const block of ensureList(content)) {
      if (typeof block === 'string') {
        if (block.trim()) {
          textParts.push(block.trim())
        }
        continue
      }
      if (block === null || typeof block !== 'object' || Array.isArray(block)) {
        continue
      }
      const rec = block as Record<string, unknown>
      const blockType = String(rec['type'] ?? '').toLowerCase()

      if (TEXT_BLOCK_TYPES.has(blockType)) {
        const text = String(rec['text'] ?? '').trim()
        if (text) {
          textParts.push(text)
        }
        continue
      }
      if (SKIP_BLOCK_TYPES.has(blockType)) {
        continue
      }
      if (TOOL_USE_TYPES.has(blockType)) {
        const name = String(rec['name'] ?? '') || 'tool_use'
        toolEvents.push({
          summary: `${name} input=${summarizeValue(rec['input'])}`,
          timestamp,
        })
        continue
      }
      if (TOOL_RESULT_TYPES.has(blockType)) {
        const toolUseId = String(rec['tool_use_id'] ?? '') || 'tool_result'
        toolEvents.push({
          summary: `${toolUseId} output=${summarizeValue(rec['content'])}`,
          timestamp,
        })
      }
    }

    const text = joinParagraphs(textParts)
    if ((role === 'user' || role === 'assistant') && text) {
      messages.push({ role, text, timestamp })
    }
  }

  return {
    client: 'claude',
    session_id: sessionId,
    title,
    started_at: startedAt,
    cwd,
    branch,
    messages: deduplicateMessages(messages),
    tool_events: deduplicateToolEvents(toolEvents),
    source_path: filePath,
  }
}

// ---------------------------------------------------------------------------
// Gemini parser
// ---------------------------------------------------------------------------

export function parseGeminiTranscript(filePath: string): ParsedTranscript {
  const stem = basename(filePath, extname(filePath))
  let sessionId = stem
  const title = stem
  let startedAt = normalizeTimestamp(statSync(filePath).mtimeMs / 1000)
  let cwd = ''
  let branch = ''
  const messages: TranscriptMessage[] = []
  const toolEvents: TranscriptToolEvent[] = []

  let payload: unknown
  if (extname(filePath).toLowerCase() === '.jsonl') {
    payload = loadJsonl(filePath)
  } else {
    payload = JSON.parse(readFileSync(filePath, 'utf-8')) as unknown
  }

  const metaKeys: ReadonlySet<string> = new Set(['sessionId', 'chatId', 'cwd', 'branch', 'timestamp'])
  const firstMeta = findFirstMappingWithKeys(payload, metaKeys)
  if (firstMeta !== null) {
    sessionId = String(firstMeta['sessionId'] ?? '') || String(firstMeta['chatId'] ?? '') || String(firstMeta['id'] ?? '') || sessionId
    startedAt = earliestTimestamp(startedAt, firstMeta['timestamp'])
    cwd = String(firstMeta['cwd'] ?? '') || String(firstMeta['projectRoot'] ?? '') || cwd
    branch = String(firstMeta['branch'] ?? '') || branch
  }

  function visit(node: unknown): void {
    if (Array.isArray(node)) {
      for (const item of node) {
        visit(item)
      }
      return
    }
    if (node === null || typeof node !== 'object') {
      return
    }
    const rec = node as Record<string, unknown>

    sessionId = String(rec['sessionId'] ?? '') || String(rec['chatId'] ?? '') || String(rec['id'] ?? '') || sessionId
    startedAt = earliestTimestamp(startedAt, rec['timestamp'])
    cwd = String(rec['cwd'] ?? '') || String(rec['projectRoot'] ?? '') || cwd
    branch = String(rec['branch'] ?? '') || branch

    const role = String(rec['role'] ?? rec['author'] ?? rec['sender'] ?? '').toLowerCase()
    const timestamp = normalizeTimestamp(rec['timestamp'], startedAt)

    if (role === 'user' || role === 'assistant' || role === 'model') {
      const normalizedRole = role === 'model' ? 'assistant' : role
      const text = extractGeminiText(rec)
      if (text) {
        messages.push({ role: normalizedRole, text, timestamp })
      }
    }

    const toolName =
      getNested(rec, 'toolUse', 'name') ??
      rec['toolName'] ??
      rec['functionName'] ??
      rec['tool']
    if (toolName) {
      toolEvents.push({
        summary: `${String(toolName)} input=${summarizeValue(rec['args'] ?? rec['input'])}`,
        timestamp,
      })
    }

    for (const value of Object.values(rec)) {
      visit(value)
    }
  }

  visit(payload)

  return {
    client: 'gemini',
    session_id: sessionId,
    title,
    started_at: startedAt,
    cwd,
    branch,
    messages: deduplicateMessages(messages),
    tool_events: deduplicateToolEvents(toolEvents),
    source_path: filePath,
  }
}

/**
 * Transcript search index — SQLite upsert for the global transcript catalog.
 *
 * Uses sql.js (WebAssembly SQLite) so the module works without a native
 * sqlite3 binding.  The WASM init is async; we cache the resulting factory
 * promise so it is only resolved once per process.
 */

import initSqlJs, { type SqlJsStatic } from 'sql.js'
import { existsSync, readFileSync, writeFileSync } from 'node:fs'
import type { ManifestEntry } from '../types/transcript.js'

// ---------------------------------------------------------------------------
// Lazy sql.js initialisation (cached promise)
// ---------------------------------------------------------------------------

let sqlPromise: Promise<SqlJsStatic> | null = null

function getSqlJs(): Promise<SqlJsStatic> {
  if (sqlPromise === null) {
    sqlPromise = initSqlJs()
  }
  return sqlPromise
}

// ---------------------------------------------------------------------------
// Column definitions
// ---------------------------------------------------------------------------

const PK_COLUMNS = [
  'client',
  'project',
  'session_id',
  'raw_sha256',
] as const

const DATA_COLUMNS = [
  'title',
  'started_at',
  'imported_at',
  'cwd',
  'branch',
  'raw_source_path',
  'raw_upload_permission',
  'global_raw_path',
  'global_clean_path',
  'repo_raw_path',
  'repo_clean_path',
  'repo_manifest_path',
  'message_count',
  'tool_event_count',
] as const

const ALL_COLUMNS = [...PK_COLUMNS, ...DATA_COLUMNS] as const

// ---------------------------------------------------------------------------
// SQL statements (built once)
// ---------------------------------------------------------------------------

const CREATE_TABLE_SQL = `
  CREATE TABLE IF NOT EXISTS transcripts (
    client              TEXT    NOT NULL,
    project             TEXT    NOT NULL,
    session_id          TEXT    NOT NULL,
    raw_sha256          TEXT    NOT NULL,
    title               TEXT    NOT NULL,
    started_at          TEXT    NOT NULL,
    imported_at         TEXT    NOT NULL,
    cwd                 TEXT    NOT NULL,
    branch              TEXT    NOT NULL,
    raw_source_path     TEXT    NOT NULL,
    raw_upload_permission TEXT  NOT NULL,
    global_raw_path     TEXT    NOT NULL,
    global_clean_path   TEXT    NOT NULL,
    repo_raw_path       TEXT    NOT NULL,
    repo_clean_path     TEXT    NOT NULL,
    repo_manifest_path  TEXT    NOT NULL,
    message_count       INTEGER NOT NULL,
    tool_event_count    INTEGER NOT NULL,
    PRIMARY KEY (client, project, session_id, raw_sha256)
  )
`

const UPSERT_SQL = `
  INSERT INTO transcripts (
    ${ALL_COLUMNS.join(', ')}
  ) VALUES (${ALL_COLUMNS.map(() => '?').join(', ')})
  ON CONFLICT(${PK_COLUMNS.join(', ')}) DO UPDATE SET
    ${DATA_COLUMNS.map((c) => `${c} = excluded.${c}`).join(',\n    ')}
`

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Insert or update a single transcript manifest row in the SQLite search
 * index at `dbPath`.  Creates the database and table if they do not exist.
 *
 * The function is async because the first call must initialise the sql.js
 * WASM module.
 */
export async function upsertSearchIndex(
  dbPath: string,
  manifest: ManifestEntry,
): Promise<void> {
  const SQL = await getSqlJs()

  const db = existsSync(dbPath)
    ? new SQL.Database(readFileSync(dbPath))
    : new SQL.Database()

  try {
    db.run('PRAGMA journal_mode=WAL')
    db.run(CREATE_TABLE_SQL)

    const record: Record<string, unknown> = { ...manifest }
    const params = ALL_COLUMNS.map((col) => {
      const value = record[col]
      if (value === undefined || value === null) {
        return ''
      }
      return typeof value === 'number' ? value : String(value)
    })

    db.run(UPSERT_SQL, params)

    const data = db.export()
    writeFileSync(dbPath, Buffer.from(data))
  } finally {
    db.close()
  }
}

/**
 * Transcript discovery — file scanning and project matching.
 * Port of scripts/_transcript_discover.py
 */

import { existsSync, statSync } from 'node:fs'
import { homedir } from 'node:os'
import { basename, dirname, resolve } from 'node:path'

import fg from 'fast-glob'

import type { ParsedTranscript } from '../types/transcript.js'
import { slugify, CLIENTS } from './common.js'
import { toPosixPath } from '../utils/path.js'

// ---------------------------------------------------------------------------
// Glob patterns per client
// ---------------------------------------------------------------------------

const CLIENT_PATTERNS: Readonly<Record<string, readonly string[]>> = {
  codex: ['sessions/**/*.jsonl'],
  claude: ['projects/**/*.jsonl'],
  gemini: [
    'tmp/*/checkpoints/**/*.json',
    'tmp/*/checkpoints/**/*.jsonl',
    'history/**/*.json',
    'history/**/*.jsonl',
    'chats/**/*.json',
    'chats/**/*.jsonl',
  ],
}

// ---------------------------------------------------------------------------
// Defaults
// ---------------------------------------------------------------------------

export function defaultGlobalTranscriptRoot(): string {
  return toPosixPath(resolve(homedir(), '.memorytree', 'transcripts'))
}

export function defaultClientRoots(): Record<string, string> {
  const home = homedir()
  return {
    codex: resolve(home, '.codex'),
    claude: resolve(home, '.claude'),
    gemini: resolve(home, '.gemini'),
  }
}

// ---------------------------------------------------------------------------
// File discovery
// ---------------------------------------------------------------------------

export function discoverSourceFiles(
  clients?: ReadonlySet<string>,
  roots?: Readonly<Record<string, string>>,
): Array<[string, string]> {
  const requested = clients ?? CLIENTS
  const resolvedRoots = roots ?? defaultClientRoots()
  const matches: Array<[string, string]> = []
  const seen = new Set<string>()

  for (const client of [...requested].sort()) {
    const root: string | undefined = resolvedRoots[client]
    if (root === undefined || !existsSync(root)) continue

    const patterns = CLIENT_PATTERNS[client]
    if (patterns === undefined) continue

    for (const pattern of patterns) {
      const paths = fg.sync(pattern, { cwd: root, absolute: true, onlyFiles: true })
      for (const filePath of paths) {
        const resolved = toPosixPath(resolve(filePath))
        const key = resolved.toLowerCase()
        if (seen.has(key)) continue
        seen.add(key)
        matches.push([client, resolved])
      }
    }
  }

  matches.sort((a, b) => {
    const mtimeA = safeFileMtime(a[1])
    const mtimeB = safeFileMtime(b[1])
    if (mtimeB !== mtimeA) return mtimeB - mtimeA
    const pathA = a[1].toLowerCase()
    const pathB = b[1].toLowerCase()
    // Reverse sort: higher path string comes first (matching Python's reverse=True)
    if (pathB > pathA) return 1
    if (pathB < pathA) return -1
    return 0
  })

  return matches
}

// ---------------------------------------------------------------------------
// Project slug inference
// ---------------------------------------------------------------------------

export function inferProjectSlug(parsed: ParsedTranscript): string {
  if (parsed.cwd) {
    try {
      const cwdBase = basename(parsed.cwd)
      return slugify(cwdBase, 'project')
    } catch {
      // fall through
    }
  }

  if (parsed.client === 'claude') {
    let parentName = basename(dirname(parsed.source_path)).toLowerCase()
    parentName = parentName.replace(/^[a-z]--/, '')
    return slugify(parentName, 'project')
  }

  if (parsed.client === 'gemini') {
    const parentDir = basename(dirname(parsed.source_path))
    if (parentDir) {
      return slugify(parentDir, 'project')
    }
  }

  return 'unknown-project'
}

// ---------------------------------------------------------------------------
// Repo matching
// ---------------------------------------------------------------------------

export function transcriptMatchesRepo(
  parsed: ParsedTranscript,
  repoRoot: string,
  repoSlug: string,
): boolean {
  const normalizedRepo = toPosixPath(resolve(repoRoot)).toLowerCase()

  if (parsed.cwd) {
    try {
      const normalizedCwd = toPosixPath(resolve(parsed.cwd)).toLowerCase()
      if (normalizedCwd === normalizedRepo) return true
      // Check if repoRoot is a parent of cwd
      const repoPrefix = normalizedRepo.endsWith('/')
        ? normalizedRepo
        : normalizedRepo + '/'
      if (normalizedCwd.startsWith(repoPrefix)) return true
    } catch {
      // fall through
    }
  }

  return projectSlugsMatch(inferProjectSlug(parsed), repoSlug)
}

// ---------------------------------------------------------------------------
// Slug matching
// ---------------------------------------------------------------------------

export function projectSlugsMatch(left: string, right: string): boolean {
  return Boolean(
    left && right && left === right && left !== 'unknown-project',
  )
}

// ---------------------------------------------------------------------------
// Safe mtime
// ---------------------------------------------------------------------------

export function safeFileMtime(filePath: string): number {
  try {
    return statSync(filePath).mtimeMs / 1000
  } catch {
    return 0
  }
}

/**
 * Transcript import — orchestration, cleaning, and manifest management.
 * Port of scripts/_transcript_import.py
 */

import { copyFileSync, existsSync, mkdirSync, readFileSync, writeFileSync, appendFileSync } from 'node:fs'
import { dirname, extname, join, relative } from 'node:path'

import type { ManifestEntry, ParsedTranscript } from '../types/transcript.js'
import { toPosixPath } from '../utils/path.js'
import {
  loadJson,
  normalizeTimestamp,
  sha256File,
  slugify,
  timestampPartition,
  yamlEscape,
} from './common.js'
import { upsertSearchIndex } from './db.js'

export async function importTranscript(
  parsed: ParsedTranscript,
  root: string,
  globalRoot: string,
  projectSlug: string,
  rawUploadPermission: string,
  mirrorToRepo = true,
): Promise<ManifestEntry> {
  const importedAt = normalizeTimestamp(new Date())
  const rawSha256 = sha256File(parsed.source_path)
  const sessionLabel = slugify(
    parsed.session_id,
    slugify(stemOf(parsed.source_path), 'session'),
  )
  const artifactStem = `${sessionLabel}__${rawSha256.slice(0, 8)}`
  const sourceSuffix = extname(parsed.source_path) || '.txt'

  const [yearToken, monthToken] = timestampPartition(parsed.started_at || importedAt)

  const repoRoot = join(root, 'Memory', '06_transcripts')
  const repoRawPath = join(repoRoot, 'raw', parsed.client, yearToken, monthToken, `${artifactStem}${sourceSuffix}`)
  const repoCleanPath = join(repoRoot, 'clean', parsed.client, yearToken, monthToken, `${artifactStem}.md`)
  const repoManifestPath = join(repoRoot, 'manifests', parsed.client, yearToken, monthToken, `${artifactStem}.json`)

  const globalRawPath = join(globalRoot, 'raw', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}${sourceSuffix}`)
  const globalCleanPath = join(globalRoot, 'clean', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}.md`)
  const globalManifestPath = join(globalRoot, 'index', 'manifests', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}.json`)
  const globalEventLogPath = join(globalRoot, 'index', 'sessions.jsonl')
  const globalDbPath = join(globalRoot, 'index', 'search.sqlite')

  for (const p of [globalRawPath, globalCleanPath, globalManifestPath, globalEventLogPath, globalDbPath]) {
    mkdirSync(dirname(p), { recursive: true })
  }
  if (mirrorToRepo) {
    for (const p of [repoRawPath, repoCleanPath, repoManifestPath]) {
      mkdirSync(dirname(p), { recursive: true })
    }
  }

  if (mirrorToRepo) {
    copyFile(parsed.source_path, repoRawPath)
  }
  copyFile(parsed.source_path, globalRawPath)

  let manifest: ManifestEntry = {
    client: parsed.client,
    project: projectSlug,
    session_id: parsed.session_id,
    title: parsed.title,
    started_at: parsed.started_at,
    imported_at: importedAt,
    cwd: parsed.cwd,
    branch: parsed.branch,
    raw_source_path: toPosixPath(parsed.source_path),
    raw_sha256: rawSha256,
    raw_upload_permission: rawUploadPermission,
    repo_raw_path: mirrorToRepo ? toPosixPath(relative(root, repoRawPath)) : '',
    repo_clean_path: mirrorToRepo ? toPosixPath(relative(root, repoCleanPath)) : '',
    repo_manifest_path: mirrorToRepo ? toPosixPath(relative(root, repoManifestPath)) : '',
    global_raw_path: toPosixPath(globalRawPath),
    global_clean_path: toPosixPath(globalCleanPath),
    global_manifest_path: toPosixPath(globalManifestPath),
    message_count: parsed.messages.length,
    tool_event_count: parsed.tool_events.length,
    cleaning_mode: 'deterministic-code',
    repo_mirror_enabled: mirrorToRepo,
  }

  const existingGlobalManifest = loadJson(globalManifestPath)
  manifest = preserveExistingImportTimestamp(existingGlobalManifest, manifest)

  if (mirrorToRepo) {
    writeCleanMarkdown(parsed, manifest, repoCleanPath)
  }
  writeCleanMarkdown(parsed, manifest, globalCleanPath)
  if (mirrorToRepo) {
    writeJson(repoManifestPath, manifest)
  }
  const appendToEventLog = existingGlobalManifest === null || !deepEqual(existingGlobalManifest, manifest)
  writeJson(globalManifestPath, manifest)
  if (appendToEventLog) {
    appendJsonl(globalEventLogPath, manifest)
  }
  await upsertSearchIndex(globalDbPath, manifest)

  return manifest
}

export function transcriptHasContent(parsed: ParsedTranscript): boolean {
  return parsed.messages.length > 0 || parsed.tool_events.length > 0
}

export function writeCleanMarkdown(parsed: ParsedTranscript, manifest: ManifestEntry, filePath: string): void {
  const lines: string[] = [
    '---',
    `client: ${manifest.client}`,
    `project: ${manifest.project}`,
    `session_id: ${manifest.session_id}`,
    `title: ${yamlEscape(manifest.title)}`,
    `started_at: ${manifest.started_at}`,
    `imported_at: ${manifest.imported_at}`,
    `cwd: ${yamlEscape(manifest.cwd)}`,
    `branch: ${yamlEscape(manifest.branch)}`,
    `raw_source_path: ${yamlEscape(manifest.raw_source_path)}`,
    `raw_sha256: ${manifest.raw_sha256}`,
    `raw_upload_permission: ${manifest.raw_upload_permission}`,
    `cleaning_mode: ${manifest.cleaning_mode}`,
    '---',
    '',
    `# ${manifest.title || manifest.session_id}`,
    '',
    '## Metadata',
    `- Client: \`${manifest.client}\``,
    `- Project: \`${manifest.project}\``,
    `- Session ID: \`${manifest.session_id}\``,
    `- Started At: \`${manifest.started_at}\``,
    `- Imported At: \`${manifest.imported_at}\``,
    `- Raw SHA256: \`${manifest.raw_sha256}\``,
    `- Raw Source: \`${manifest.raw_source_path}\``,
    `- Repo Raw Path: \`${manifest.repo_raw_path}\``,
    `- Repo Clean Path: \`${manifest.repo_clean_path}\``,
    '',
    '## Messages',
  ]

  if (parsed.messages.length > 0) {
    for (let i = 0; i < parsed.messages.length; i++) {
      const message = parsed.messages[i]!
      lines.push(
        `### ${i + 1}. ${message.role}`,
        `- Timestamp: \`${message.timestamp ?? manifest.started_at}\``,
        '',
        message.text,
        '',
      )
    }
  } else {
    lines.push(
      'No user or assistant messages were extracted deterministically from the source transcript.',
      '',
    )
  }

  lines.push('## Tool Events')
  if (parsed.tool_events.length > 0) {
    for (const event of parsed.tool_events) {
      lines.push(`- \`${event.timestamp ?? manifest.started_at}\` ${event.summary}`)
    }
  } else {
    lines.push('- No tool events were extracted.')
  }
  lines.push('')

  writeFileSync(filePath, lines.join('\n'), 'utf-8')
}

export function preserveExistingImportTimestamp(
  existing: Record<string, unknown> | null,
  payload: ManifestEntry,
): ManifestEntry {
  if (existing === null) return payload
  if (!deepEqual(manifestSignature(existing), manifestSignature(payload))) return payload
  const importedAt = existing['imported_at']
  if (typeof importedAt === 'string' && importedAt) {
    return { ...payload, imported_at: importedAt }
  }
  return payload
}

export function manifestSignature(payload: Record<string, unknown>): Record<string, unknown> {
  const result: Record<string, unknown> = {}
  for (const [key, value] of Object.entries(payload)) {
    if (key !== 'imported_at') {
      result[key] = value
    }
  }
  return result
}

export function manifestChanged(filePath: string, payload: Record<string, unknown>): boolean {
  if (!existsSync(filePath)) return true
  try {
    const current = JSON.parse(readFileSync(filePath, 'utf-8')) as Record<string, unknown>
    return !deepEqual(current, payload)
  } catch {
    return true
  }
}

export function writeJson(filePath: string, payload: Record<string, unknown>): void {
  writeFileSync(filePath, JSON.stringify(payload, null, 2) + '\n', 'utf-8')
}

export function appendJsonl(filePath: string, payload: Record<string, unknown>): void {
  appendFileSync(filePath, JSON.stringify(payload) + '\n', 'utf-8')
}

export function copyFile(source: string, destination: string): void {
  if (source === destination) return
  copyFileSync(source, destination)
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function stemOf(filePath: string): string {
  const base = filePath.replace(/\\/g, '/').split('/').pop() ?? ''
  const ext = extname(base)
  return ext ? base.slice(0, -ext.length) : base
}

function deepEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true
  if (a === null || b === null || typeof a !== typeof b) return false
  if (typeof a !== 'object') return false
  if (Array.isArray(a) !== Array.isArray(b)) return false
  const aObj = a as Record<string, unknown>
  const bObj = b as Record<string, unknown>
  const aKeys = Object.keys(aObj)
  const bKeys = Object.keys(bObj)
  if (aKeys.length !== bKeys.length) return false
  return aKeys.every(key => deepEqual(aObj[key], bObj[key]))
}

