    expect(findFirstMappingWithKeys({ a: 1 }, new Set(['missing']))).toBeNull()
  })
  it('returns null for primitive', () => {
    expect(findFirstMappingWithKeys('string', new Set(['key']))).toBeNull()
  })
})

