        role: 'user',
        content: [{ type: 'text', text: 'Hello' }],
      },
    })
    writeFileSync(filePath, `${record}\n${record}\n`)

    const result = parseCodexTranscript(filePath)
    expect(result.messages).toHaveLength(1)
  })

