export function buildDatetime(dateValue: string, timeValue: string): Date {
  if (dateValue && timeValue) {
    return new Date(`${dateValue}T${timeValue}:00`)
  }
  if (dateValue) {
    return new Date(`${dateValue}T00:00:00`)
  }
  if (timeValue) {
