/**
 * Shared constants, data-access helpers, text-extraction utilities, and dedup.
 * Port of scripts/_transcript_common.py
 */

import { createHash } from 'node:crypto'
import { readFileSync, existsSync } from 'node:fs'

import type { TranscriptMessage, TranscriptToolEvent } from '../types/transcript.js'

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

export const CLIENTS: ReadonlySet<string> = new Set(['codex', 'claude', 'gemini'])
export const TEXT_BLOCK_TYPES: ReadonlySet<string> = new Set(['input_text', 'output_text', 'text'])
export const SKIP_BLOCK_TYPES: ReadonlySet<string> = new Set(['thinking', 'reasoning'])
export const TOOL_USE_TYPES: ReadonlySet<string> = new Set(['tool_use'])
export const TOOL_RESULT_TYPES: ReadonlySet<string> = new Set(['tool_result'])

// ---------------------------------------------------------------------------
// Generic utilities
// ---------------------------------------------------------------------------

export function slugify(value: string, fallback = 'session'): string {
  // eslint-disable-next-line no-control-regex
  const asciiValue = value.replace(/[^\x00-\x7F]/g, '').toLowerCase()
  const slug = asciiValue.replace(/[^a-z0-9._-]+/g, '-').replace(/^[-._]+|[-._]+$/g, '')
  return slug || fallback
}

export function sha256File(filePath: string): string {
  const data = readFileSync(filePath)
  return createHash('sha256').update(data).digest('hex')
}

export function contentHash(text: string): string {
  return createHash('sha256').update(text, 'utf8').digest('hex').slice(0, 16)
}

export function normalizeTimestamp(value: unknown, fallback?: string | null): string {
  if (typeof value === 'number') {
    const ms = value < 1e12 ? value * 1000 : value
    const d = new Date(ms)
    return formatUtcIso(d)
  }

  if (value instanceof Date) {
    return formatUtcIso(value)
  }

  if (typeof value === 'string') {
    const text = value.trim()
    if (!text) {
      return fallback ?? normalizeTimestamp(new Date())
    }
    const parsed = parseIsoTimestamp(text)
    if (parsed !== null) {
      return formatUtcIso(parsed)
    }
    return text
  }

  return fallback ?? normalizeTimestamp(new Date())
}

export function earliestTimestamp(current: string, candidate: unknown): string {
  const normalized = normalizeTimestamp(candidate, current)
  const currentDt = parseIsoTimestamp(current)
  const normalizedDt = parseIsoTimestamp(normalized)
  if (currentDt !== null && normalizedDt !== null) {
    return normalizedDt < currentDt ? normalized : current
  }
  if (normalizedDt !== null) {
    return normalized
  }
  return current || normalized
}

export function parseIsoTimestamp(value: string): Date | null {
  if (!value) return null
  const candidate = value.endsWith('Z') ? value.slice(0, -1) + '+00:00' : value
  const d = new Date(candidate)
  if (isNaN(d.getTime())) return null
  return d
}

export function timestampPartition(timestamp: string): [string, string] {
  const d = parseIsoTimestamp(timestamp)
  if (d === null) return ['unknown', 'unknown']
  const year = d.getUTCFullYear().toString()
  const month = (d.getUTCMonth() + 1).toString().padStart(2, '0')
  return [year, month]
}

export function joinParagraphs(parts: Iterable<string>): string {
  const cleaned: string[] = []
  for (const part of parts) {
    const trimmed = String(part).trim()
    if (trimmed) cleaned.push(trimmed)
  }
  return cleaned.join('\n\n')
}

export function summarizeValue(value: unknown, limit = 180): string {
  if (value === null || value === undefined) return 'none'
  if (typeof value === 'string') {
    const text = value.replace(/\s+/g, ' ').trim()
    return truncate(text, limit)
  }
  let text: string
  try {
    text = JSON.stringify(value, Object.keys(value as Record<string, unknown>).sort())
  } catch {
    text = String(value)
  }
  text = text.replace(/\s+/g, ' ').trim()
  return truncate(text, limit)
}

export function truncate(text: string, limit: number): string {
  return text.length <= limit ? text : text.slice(0, limit - 3) + '...'
}

export function yamlEscape(value: string): string {
  const escaped = value.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, '\\n')
  return `"${escaped}"`
}

// ---------------------------------------------------------------------------
// Data access helpers
// ---------------------------------------------------------------------------

export function ensureDict(value: unknown): Record<string, unknown> {
  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
    return value as Record<string, unknown>
  }
  return {}
}

export function ensureList(value: unknown): unknown[] {
  return Array.isArray(value) ? value : []
}

export function getNested(payload: Record<string, unknown>, ...keys: string[]): unknown {
  let current: unknown = payload
  for (const key of keys) {
    if (current === null || typeof current !== 'object' || Array.isArray(current)) {
      return null
    }
    current = (current as Record<string, unknown>)[key]
  }
  return current ?? null
}

export function loadJsonl(filePath: string): Record<string, unknown>[] {
  let content: string
  try {
    content = readFileSync(filePath, 'utf-8')
  } catch {
    return []
  }
  const records: Record<string, unknown>[] = []
  for (const line of content.split('\n')) {
    const trimmed = line.trim()
    if (!trimmed) continue
    try {
      records.push(JSON.parse(trimmed) as Record<string, unknown>)
    } catch {
      continue
    }
  }
  return records
}

export function loadJson(filePath: string): Record<string, unknown> | null {
  if (!existsSync(filePath)) return null
  try {
    const text = readFileSync(filePath, 'utf-8')
    return JSON.parse(text) as Record<string, unknown>
  } catch {
    return null
  }
}

// ---------------------------------------------------------------------------
// Text extraction helpers
// ---------------------------------------------------------------------------

export function extractTextBlocks(blocks: unknown): string {
  const parts: string[] = []
  const skipTypes = new Set([...SKIP_BLOCK_TYPES, ...TOOL_USE_TYPES, ...TOOL_RESULT_TYPES])

  for (const block of ensureList(blocks)) {
    if (typeof block === 'string') {
      const text = block.trim()
      if (text) parts.push(text)
      continue
    }
    if (block === null || typeof block !== 'object' || Array.isArray(block)) continue

    const rec = block as Record<string, unknown>
    const blockType = String(rec['type'] ?? '').toLowerCase()
    if (skipTypes.has(blockType)) continue
    if (TEXT_BLOCK_TYPES.has(blockType)) {
      const text = String(rec['text'] ?? '').trim()
      if (text) parts.push(text)
      continue
    }
    const fallbackText = extractSimpleText(block)
    if (fallbackText) parts.push(fallbackText)
  }
  return joinParagraphs(parts)
}

export function extractSimpleText(value: unknown): string {
  if (typeof value === 'string') return value.trim()
  if (Array.isArray(value)) {
    return joinParagraphs(value.map(item => extractSimpleText(item)))
  }
  if (value !== null && typeof value === 'object') {
    const rec = value as Record<string, unknown>
    for (const key of ['text', 'content', 'value']) {
      if (key in rec && typeof rec[key] === 'string') {
        return (rec[key] as string).trim()
      }
    }
    return ''
  }
  return ''
}

export function extractGeminiText(node: Record<string, unknown>): string {
  const parts: string[] = []
  for (const key of ['parts', 'content', 'text', 'message']) {
    parts.push(...extractGeminiParts(node[key]))
  }
  return joinParagraphs(parts)
}

export function extractGeminiParts(value: unknown): string[] {
  if (typeof value === 'string') {
    const text = value.trim()
    return text ? [text] : []
  }
  if (Array.isArray(value)) {
    const parts: string[] = []
    for (const item of value) {
      parts.push(...extractGeminiParts(item))
    }
    return parts
  }
  if (value !== null && typeof value === 'object') {
    const rec = value as Record<string, unknown>
    const blockType = String(rec['type'] ?? '').toLowerCase()
    const skipTypes = new Set([...SKIP_BLOCK_TYPES, ...TOOL_USE_TYPES, ...TOOL_RESULT_TYPES])
    if (skipTypes.has(blockType)) return []
    if ('text' in rec && typeof rec['text'] === 'string') {
      const text = (rec['text'] as string).trim()
      return text ? [text] : []
    }
    const parts: string[] = []
    for (const key of ['parts', 'content']) {
      if (key in rec) {
        parts.push(...extractGeminiParts(rec[key]))
      }
    }
    return parts
  }
  return []
}

export function findFirstMappingWithKeys(value: unknown, keys: ReadonlySet<string>): Record<string, unknown> | null {
  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
    const rec = value as Record<string, unknown>
    const recKeys = Object.keys(rec)
    if (recKeys.some(k => keys.has(k))) return rec
    for (const v of Object.values(rec)) {
      const result = findFirstMappingWithKeys(v, keys)
      if (result !== null) return result
    }
    return null
  }
  if (Array.isArray(value)) {
    for (const item of value) {
      const result = findFirstMappingWithKeys(item, keys)
      if (result !== null) return result
    }
  }
  return null
}

// ---------------------------------------------------------------------------
// Deduplication helpers
// ---------------------------------------------------------------------------

export function deduplicateMessages(messages: readonly TranscriptMessage[]): TranscriptMessage[] {
  const seen = new Set<string>()
  const result: TranscriptMessage[] = []
  for (const msg of messages) {
    const sig = `${msg.timestamp ?? ''}\0${msg.role}\0${contentHash(msg.text)}`
    if (!seen.has(sig)) {
      seen.add(sig)
      result.push(msg)
    }
  }
  return result
}

export function deduplicateToolEvents(events: readonly TranscriptToolEvent[]): TranscriptToolEvent[] {
  const seen = new Set<string>()
  const result: TranscriptToolEvent[] = []
  for (const evt of events) {
    const sig = `${evt.timestamp ?? ''}\0${contentHash(evt.summary)}`
    if (!seen.has(sig)) {
      seen.add(sig)
      result.push(evt)
    }
  }
  return result
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function formatUtcIso(d: Date): string {
  const year = d.getUTCFullYear()
  const month = String(d.getUTCMonth() + 1).padStart(2, '0')
  const day = String(d.getUTCDate()).padStart(2, '0')
  const hours = String(d.getUTCHours()).padStart(2, '0')
  const minutes = String(d.getUTCMinutes()).padStart(2, '0')
  const seconds = String(d.getUTCSeconds()).padStart(2, '0')
  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}Z`
}

/**
 * Transcript import — orchestration, cleaning, and manifest management.
 * Port of scripts/_transcript_import.py
 */

import { copyFileSync, existsSync, mkdirSync, readFileSync, writeFileSync, appendFileSync } from 'node:fs'
import { dirname, extname, join, relative } from 'node:path'

import type { ManifestEntry, ParsedTranscript } from '../types/transcript.js'
import { toPosixPath } from '../utils/path.js'
import {
  loadJson,
  normalizeTimestamp,
  sha256File,
  slugify,
  timestampPartition,
  yamlEscape,
} from './common.js'
import { upsertSearchIndex } from './db.js'

export async function importTranscript(
  parsed: ParsedTranscript,
  root: string,
  globalRoot: string,
  projectSlug: string,
  rawUploadPermission: string,
  mirrorToRepo = true,
): Promise<ManifestEntry> {
  const importedAt = normalizeTimestamp(new Date())
  const rawSha256 = sha256File(parsed.source_path)
  const sessionLabel = slugify(
    parsed.session_id,
    slugify(stemOf(parsed.source_path), 'session'),
  )
  const artifactStem = `${sessionLabel}__${rawSha256.slice(0, 8)}`
  const sourceSuffix = extname(parsed.source_path) || '.txt'

  const [yearToken, monthToken] = timestampPartition(parsed.started_at || importedAt)

  const repoRoot = join(root, 'Memory', '06_transcripts')
  const repoRawPath = join(repoRoot, 'raw', parsed.client, yearToken, monthToken, `${artifactStem}${sourceSuffix}`)
  const repoCleanPath = join(repoRoot, 'clean', parsed.client, yearToken, monthToken, `${artifactStem}.md`)
  const repoManifestPath = join(repoRoot, 'manifests', parsed.client, yearToken, monthToken, `${artifactStem}.json`)

  const globalRawPath = join(globalRoot, 'raw', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}${sourceSuffix}`)
  const globalCleanPath = join(globalRoot, 'clean', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}.md`)
  const globalManifestPath = join(globalRoot, 'index', 'manifests', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}.json`)
  const globalEventLogPath = join(globalRoot, 'index', 'sessions.jsonl')
  const globalDbPath = join(globalRoot, 'index', 'search.sqlite')

  for (const p of [globalRawPath, globalCleanPath, globalManifestPath, globalEventLogPath, globalDbPath]) {
    mkdirSync(dirname(p), { recursive: true })
  }
  if (mirrorToRepo) {
    for (const p of [repoRawPath, repoCleanPath, repoManifestPath]) {
      mkdirSync(dirname(p), { recursive: true })
    }
  }

  if (mirrorToRepo) {
    copyFile(parsed.source_path, repoRawPath)
  }
  copyFile(parsed.source_path, globalRawPath)

  let manifest: ManifestEntry = {
    client: parsed.client,
    project: projectSlug,
    session_id: parsed.session_id,
    title: parsed.title,
    started_at: parsed.started_at,
    imported_at: importedAt,
    cwd: parsed.cwd,
    branch: parsed.branch,
    raw_source_path: toPosixPath(parsed.source_path),
    raw_sha256: rawSha256,
    raw_upload_permission: rawUploadPermission,
    repo_raw_path: mirrorToRepo ? toPosixPath(relative(root, repoRawPath)) : '',
    repo_clean_path: mirrorToRepo ? toPosixPath(relative(root, repoCleanPath)) : '',
    repo_manifest_path: mirrorToRepo ? toPosixPath(relative(root, repoManifestPath)) : '',
    global_raw_path: toPosixPath(globalRawPath),
    global_clean_path: toPosixPath(globalCleanPath),
    global_manifest_path: toPosixPath(globalManifestPath),
    message_count: parsed.messages.length,
    tool_event_count: parsed.tool_events.length,
    cleaning_mode: 'deterministic-code',
    repo_mirror_enabled: mirrorToRepo,
  }

  const existingGlobalManifest = loadJson(globalManifestPath)
  manifest = preserveExistingImportTimestamp(existingGlobalManifest, manifest)

  if (mirrorToRepo) {
    writeCleanMarkdown(parsed, manifest, repoCleanPath)
  }
  writeCleanMarkdown(parsed, manifest, globalCleanPath)
  const manifestRecord = { ...manifest } as Record<string, unknown>
  if (mirrorToRepo) {
    writeJson(repoManifestPath, manifestRecord)
  }
  const appendToEventLog = existingGlobalManifest === null || !deepEqual(existingGlobalManifest, manifestRecord)
  writeJson(globalManifestPath, manifestRecord)
  if (appendToEventLog) {
    appendJsonl(globalEventLogPath, manifestRecord)
  }
  await upsertSearchIndex(globalDbPath, manifest)

  return manifest
}

export function transcriptHasContent(parsed: ParsedTranscript): boolean {
  return parsed.messages.length > 0 || parsed.tool_events.length > 0
}

export function writeCleanMarkdown(parsed: ParsedTranscript, manifest: ManifestEntry, filePath: string): void {
  const lines: string[] = [
    '---',
    `client: ${manifest.client}`,
    `project: ${manifest.project}`,
    `session_id: ${manifest.session_id}`,
    `title: ${yamlEscape(manifest.title)}`,
    `started_at: ${manifest.started_at}`,
    `imported_at: ${manifest.imported_at}`,
    `cwd: ${yamlEscape(manifest.cwd)}`,
    `branch: ${yamlEscape(manifest.branch)}`,
    `raw_source_path: ${yamlEscape(manifest.raw_source_path)}`,
    `raw_sha256: ${manifest.raw_sha256}`,
    `raw_upload_permission: ${manifest.raw_upload_permission}`,
    `cleaning_mode: ${manifest.cleaning_mode}`,
    '---',
    '',
    `# ${manifest.title || manifest.session_id}`,
    '',
    '## Metadata',
    `- Client: \`${manifest.client}\``,
    `- Project: \`${manifest.project}\``,
    `- Session ID: \`${manifest.session_id}\``,
    `- Started At: \`${manifest.started_at}\``,
    `- Imported At: \`${manifest.imported_at}\``,
    `- Raw SHA256: \`${manifest.raw_sha256}\``,
    `- Raw Source: \`${manifest.raw_source_path}\``,
    `- Repo Raw Path: \`${manifest.repo_raw_path}\``,
    `- Repo Clean Path: \`${manifest.repo_clean_path}\``,
    '',
    '## Messages',
  ]

  if (parsed.messages.length > 0) {
    for (let i = 0; i < parsed.messages.length; i++) {
      const message = parsed.messages[i]!
      lines.push(
        `### ${i + 1}. ${message.role}`,
        `- Timestamp: \`${message.timestamp ?? manifest.started_at}\``,
        '',
        message.text,
        '',
      )
    }
  } else {
    lines.push(
      'No user or assistant messages were extracted deterministically from the source transcript.',
      '',
    )
  }

  lines.push('## Tool Events')
  if (parsed.tool_events.length > 0) {
    for (const event of parsed.tool_events) {
      lines.push(`- \`${event.timestamp ?? manifest.started_at}\` ${event.summary}`)
    }
  } else {
    lines.push('- No tool events were extracted.')
  }
  lines.push('')

  writeFileSync(filePath, lines.join('\n'), 'utf-8')
}

export function preserveExistingImportTimestamp(
  existing: Record<string, unknown> | null,
  payload: ManifestEntry,
): ManifestEntry {
  if (existing === null) return payload
  const payloadRecord = { ...payload } as Record<string, unknown>
  if (!deepEqual(manifestSignature(existing), manifestSignature(payloadRecord))) return payload
  const importedAt = existing['imported_at']
  if (typeof importedAt === 'string' && importedAt) {
    return { ...payload, imported_at: importedAt }
  }
  return payload
}

export function manifestSignature(payload: Record<string, unknown>): Record<string, unknown> {
  const result: Record<string, unknown> = {}
  for (const [key, value] of Object.entries(payload)) {
    if (key !== 'imported_at') {
      result[key] = value
    }
  }
  return result
}

export function manifestChanged(filePath: string, payload: Record<string, unknown>): boolean {
  if (!existsSync(filePath)) return true
  try {
    const current = JSON.parse(readFileSync(filePath, 'utf-8')) as Record<string, unknown>
    return !deepEqual(current, payload)
  } catch {
    return true
  }
}

export function writeJson(filePath: string, payload: Record<string, unknown>): void {
  writeFileSync(filePath, JSON.stringify(payload, null, 2) + '\n', 'utf-8')
}

export function appendJsonl(filePath: string, payload: Record<string, unknown>): void {
  appendFileSync(filePath, JSON.stringify(payload) + '\n', 'utf-8')
}

export function copyFile(source: string, destination: string): void {
  if (source === destination) return
  copyFileSync(source, destination)
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function stemOf(filePath: string): string {
  const base = filePath.replace(/\\/g, '/').split('/').pop() ?? ''
  const ext = extname(base)
  return ext ? base.slice(0, -ext.length) : base
}

function deepEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true
  if (a === null || b === null || typeof a !== typeof b) return false
  if (typeof a !== 'object') return false
  if (Array.isArray(a) !== Array.isArray(b)) return false
  const aObj = a as Record<string, unknown>
  const bObj = b as Record<string, unknown>
  const aKeys = Object.keys(aObj)
  const bKeys = Object.keys(bObj)
  if (aKeys.length !== bKeys.length) return false
  return aKeys.every(key => deepEqual(aObj[key], bObj[key]))
}

/**
 * MemoryTree heartbeat — single execution, stateless, idempotent.
 * Port of scripts/heartbeat.py
 */

import type { ParsedTranscript } from '../types/transcript.js'
import { discoverSourceFiles, transcriptMatchesRepo } from '../transcript/discover.js'
import { importTranscript, transcriptHasContent } from '../transcript/import.js'
import { parseTranscript } from '../transcript/parse.js'
import { slugify } from '../transcript/common.js'
import { defaultGlobalTranscriptRoot } from '../transcript/discover.js'
import type { Config } from './config.js'
import { loadConfig } from './config.js'
import { acquireLock, releaseLock } from './lock.js'
import { resetFailureCount, writeAlert, writeAlertWithThreshold } from './alert.js'
import type { LogLevel } from './log.js'
import { getLogger, setupLogging } from './log.js'
import { git } from '../utils/exec.js'
import { toPosixPath } from '../utils/path.js'
import { resolve } from 'node:path'
import { existsSync } from 'node:fs'

// ---------------------------------------------------------------------------
// Sensitive pattern detection
// ---------------------------------------------------------------------------

const SENSITIVE_PATTERNS: readonly RegExp[] = [
  /(?:api[_-]?key|apikey)\s*[:=]\s*\S+/i,
  /(?:password|passwd|pwd)\s*[:=]\s*\S+/i,
  /(?:secret|token)\s*[:=]\s*\S+/i,
  /(?:sk-|pk_live_|sk_live_|ghp_|gho_|glpat-)\S{10,}/,
  /Bearer\s+\S{20,}/i,
]

// ---------------------------------------------------------------------------
// Main entry point
// ---------------------------------------------------------------------------

export async function main(): Promise<number> {
  const config = loadConfig()
  setupLogging(config.log_level as LogLevel)
  const logger = getLogger()

  if (!acquireLock()) {
    logger.info('Another heartbeat instance is running. Exiting.')
    writeAlert('global', 'lock_held', 'Heartbeat exited: another instance held the lock.')
    return 0
  }

  try {
    return await runHeartbeat(config)
  } finally {
    releaseLock()
  }
}

// ---------------------------------------------------------------------------
// Heartbeat orchestration
// ---------------------------------------------------------------------------

export async function runHeartbeat(config: Config): Promise<number> {
  const logger = getLogger()

  if (config.projects.length === 0) {
    logger.info('No projects registered in config.toml. Nothing to do.')
    return 0
  }

  logger.info(`Heartbeat started. ${config.projects.length} project(s) registered.`)

  for (const entry of config.projects) {
    const projectPath = resolve(entry.path)
    if (!existsSync(projectPath)) {
      logger.warn(`Project path does not exist, skipping: ${projectPath}`)
      continue
    }
    try {
      await processProject(config, projectPath, entry.name || (projectPath.split(/[/\\]/).pop() ?? ''))
    } catch (err: unknown) {
      logger.exception(`Error processing project: ${projectPath}`, err)
      writeAlertWithThreshold(
        toPosixPath(projectPath),
        'push_failed',
        `Heartbeat error for project: ${projectPath.split(/[/\\]/).pop() ?? ''}`,
      )
    }
  }

  logger.info('Heartbeat finished.')
  return 0
}

// ---------------------------------------------------------------------------
// Per-project processing
// ---------------------------------------------------------------------------

export async function processProject(config: Config, projectPath: string, projectName: string): Promise<void> {
  const logger = getLogger()
  const repoSlug = slugify(projectName, 'project')
  const globalRoot = defaultGlobalTranscriptRoot()

  const discovered = discoverSourceFiles()
  let importedCount = 0

  for (const [client, source] of discovered) {
    let parsed: ParsedTranscript
    try {
      parsed = parseTranscript(client, source)
    } catch {
      logger.debug(`Failed to parse ${source}, skipping.`)
      continue
    }

    if (!transcriptHasContent(parsed)) continue
    if (!transcriptMatchesRepo(parsed, projectPath, repoSlug)) continue

    scanSensitive(parsed, projectPath)

    try {
      await importTranscript(parsed, projectPath, globalRoot, repoSlug, 'not-set', true)
      importedCount++
    } catch {
      logger.exception(`Failed to import transcript: ${source}`)
    }
  }

  if (importedCount === 0) {
    logger.info(`[${projectName}] No new transcripts to import.`)
    return
  }

  logger.info(`[${projectName}] Imported ${importedCount} transcript(s).`)
  gitCommitAndPush(config, projectPath, projectName, importedCount)
}

// ---------------------------------------------------------------------------
// Sensitive pattern scanning
// ---------------------------------------------------------------------------

export function scanSensitive(parsed: ParsedTranscript, projectPath: string): void {
  const logger = getLogger()
  for (const msg of parsed.messages) {
    for (const pattern of SENSITIVE_PATTERNS) {
      if (pattern.test(msg.text)) {
        logger.warn(
          `Sensitive pattern detected in transcript ${parsed.source_path} (project: ${projectPath.split(/[/\\]/).pop() ?? ''}, role: ${msg.role})`,
        )
        writeAlert(
          toPosixPath(projectPath),
          'sensitive_match',
          `Sensitive pattern in transcript: ${parsed.source_path.split(/[/\\]/).pop() ?? ''}`,
        )
        return
      }
    }
  }
}

// ---------------------------------------------------------------------------
// Git operations
// ---------------------------------------------------------------------------

export function gitCommitAndPush(config: Config, projectPath: string, projectName: string, count: number): void {
  const logger = getLogger()

  const status = git(projectPath, 'status', '--porcelain', 'Memory/')
  if (!status.trim()) {
    logger.info(`[${projectName}] No git changes in Memory/.`)
    return
  }

  git(projectPath, 'add', 'Memory/')
  git(projectPath, 'commit', '-m', `memorytree(transcripts): import ${count} transcript(s)`)
  logger.info(`[${projectName}] Committed ${count} transcript import(s).`)

  if (!config.auto_push) {
    logger.info(`[${projectName}] auto_push disabled, skipping push.`)
    return
  }

  const remotes = git(projectPath, 'remote')
  if (!remotes.trim()) {
    logger.warn(`[${projectName}] No git remote configured, skipping push.`)
    writeAlert(toPosixPath(projectPath), 'no_remote', 'Push skipped: no Git remote configured.')
    return
  }

  if (!tryPush(projectPath, projectName)) {
    logger.warn(`[${projectName}] Push failed, retrying once...`)
    if (!tryPush(projectPath, projectName)) {
      logger.error(`[${projectName}] Push failed after retry.`)
      writeAlertWithThreshold(toPosixPath(projectPath), 'push_failed', 'Push failed after retry.')
      return
    }
  }

  resetFailureCount(toPosixPath(projectPath), 'push_failed')
}

export function tryPush(projectPath: string, projectName: string): boolean {
  try {
    git(projectPath, 'push')
    getLogger().info(`[${projectName}] Pushed successfully.`)
    return true
  } catch {
    return false
  }
}

