/**
 * Transcript parsing — client inference, dispatch, and format-specific parsers.
 * Port of scripts/_transcript_parse.py
 */

import { readFileSync, statSync } from 'node:fs'
import { basename, extname } from 'node:path'

import type { Client, ParsedTranscript, TranscriptMessage, TranscriptToolEvent } from '../types/transcript.js'
import { toPosixPath } from '../utils/path.js'
import {
  SKIP_BLOCK_TYPES,
  TEXT_BLOCK_TYPES,
  TOOL_RESULT_TYPES,
  TOOL_USE_TYPES,
  deduplicateMessages,
  deduplicateToolEvents,
  earliestTimestamp,
  ensureDict,
  ensureList,
  extractGeminiText,
  extractTextBlocks,
  findFirstMappingWithKeys,
  getNested,
  joinParagraphs,
  loadJsonl,
  normalizeTimestamp,
  summarizeValue,
} from './common.js'

// ---------------------------------------------------------------------------
// Client inference + dispatch
// ---------------------------------------------------------------------------

export function inferClient(client: string, sourcePath: string): Client {
  if (client !== 'auto') {
    return client as Client
  }
  const normalized = toPosixPath(sourcePath).toLowerCase()
  const fileName = basename(sourcePath).toLowerCase()
  if (normalized.includes('/.codex/') || fileName.startsWith('rollout-')) {
    return 'codex'
  }
  if (normalized.includes('/.claude/') || normalized.includes('/projects/')) {
    return 'claude'
  }
  if (normalized.includes('/.gemini/') || normalized.includes('checkpoint')) {
    return 'gemini'
  }
  throw new Error(`could not infer transcript client from source path: ${sourcePath}`)
}

export function parseTranscript(client: string, sourcePath: string): ParsedTranscript {
  const resolved = inferClient(client, sourcePath)
  if (resolved === 'codex') {
    return parseCodexTranscript(sourcePath)
  }
  if (resolved === 'claude') {
    return parseClaudeTranscript(sourcePath)
  }
  if (resolved === 'gemini') {
    return parseGeminiTranscript(sourcePath)
  }
  throw new Error(`unsupported transcript client: ${resolved}`)
}

// ---------------------------------------------------------------------------
// Codex parser
// ---------------------------------------------------------------------------

export function parseCodexTranscript(filePath: string): ParsedTranscript {
  const records = loadJsonl(filePath)
  const stem = basename(filePath, extname(filePath))
  let sessionId = stem
  let title = stem
  let startedAt = normalizeTimestamp(statSync(filePath).mtimeMs / 1000)
  let cwd = ''
  let branch = ''
  const messages: TranscriptMessage[] = []
  const toolEvents: TranscriptToolEvent[] = []

  for (const record of records) {
    const recordType = String(record['type'] ?? '')
    const timestamp = normalizeTimestamp(record['timestamp'], startedAt)

    if (recordType === 'session_meta') {
      const payload = ensureDict(record['payload'])
      sessionId = String(payload['id'] ?? '') || sessionId
      title = String(payload['thread_name'] ?? '') || String(payload['title'] ?? '') || title
      startedAt = earliestTimestamp(startedAt, payload['timestamp'])
      cwd = String(payload['cwd'] ?? '') || cwd
      branch = String(getNested(payload, 'git', 'branch') ?? '') || branch
      continue
    }

    if (recordType !== 'response_item' && recordType !== 'event_msg') {
      continue
    }

    const payload = ensureDict(record['payload'])
    const payloadType = String(payload['type'] ?? '')

    if (payloadType === 'message') {
      const role = String(payload['role'] ?? '').toLowerCase()
      if (role === 'user' || role === 'assistant') {
        const text = extractTextBlocks(payload['content'])
        if (text) {
          messages.push({ role, text, timestamp })
        }
      }
      continue
    }

    if (payloadType === 'user_message' || payloadType === 'agent_message') {
      const role = payloadType === 'user_message' ? 'user' : 'assistant'
      const text = String(payload['message'] ?? '').trim()
      if (text) {
        messages.push({ role, text, timestamp })
      }
      continue
    }

    if (payloadType === 'function_call') {
      const name = String(payload['name'] ?? '') || 'function_call'
      const args = payload['arguments'] ?? payload['input']
      toolEvents.push({
        summary: `${name} input=${summarizeValue(args)}`,
        timestamp,
      })
      continue
    }

    if (payloadType === 'custom_tool_call') {
      const name = String(payload['name'] ?? '') || String(payload['call_id'] ?? '') || 'custom_tool_call'
      toolEvents.push({
        summary: `${name} input=${summarizeValue(payload['input'])}`,
        timestamp,
      })
      continue
    }

    if (payloadType === 'function_call_output') {
      const name = String(payload['name'] ?? '') || String(payload['call_id'] ?? '') || 'function_call_output'
      const output = payload['output'] ?? payload['content']
      toolEvents.push({
        summary: `${name} output=${summarizeValue(output)}`,
        timestamp,
      })
      continue
    }

    if (payloadType === 'custom_tool_call_output') {
      const name = String(payload['name'] ?? '') || String(payload['call_id'] ?? '') || 'custom_tool_call_output'
      const output = payload['output'] ?? payload['content']
      toolEvents.push({
        summary: `${name} output=${summarizeValue(output)}`,
        timestamp,
      })
    }
  }

  return {
    client: 'codex',
    session_id: sessionId,
    title,
    started_at: startedAt,
    cwd,
    branch,
    messages: deduplicateMessages(messages),
    tool_events: deduplicateToolEvents(toolEvents),
    source_path: filePath,
  }
}

// ---------------------------------------------------------------------------
// Claude parser
// ---------------------------------------------------------------------------

export function parseClaudeTranscript(filePath: string): ParsedTranscript {
  const records = loadJsonl(filePath)
  const stem = basename(filePath, extname(filePath))
  let sessionId = stem
  const title = stem
  let startedAt = normalizeTimestamp(statSync(filePath).mtimeMs / 1000)
  let cwd = ''
  let branch = ''
  const messages: TranscriptMessage[] = []
  const toolEvents: TranscriptToolEvent[] = []

  for (const record of records) {
    const recordType = String(record['type'] ?? '')
    const timestamp = normalizeTimestamp(record['timestamp'], startedAt)
    sessionId = String(record['sessionId'] ?? '') || sessionId
    startedAt = earliestTimestamp(startedAt, record['timestamp'])
    cwd = String(record['cwd'] ?? '') || cwd
    branch = String(record['gitBranch'] ?? '') || branch

    if (recordType !== 'user' && recordType !== 'assistant') {
      continue
    }

    const message = ensureDict(record['message'])
    const role = String(message['role'] ?? '').toLowerCase() || recordType
    const textParts: string[] = []
    const content = message['content']

    if (typeof content === 'string') {
      const text = content.trim()
      if ((role === 'user' || role === 'assistant') && text) {
        messages.push({ role, text, timestamp })
      }
      continue
    }

    for (const block of ensureList(content)) {
      if (typeof block === 'string') {
        if (block.trim()) {
          textParts.push(block.trim())
        }
        continue
      }
      if (block === null || typeof block !== 'object' || Array.isArray(block)) {
        continue
      }
      const rec = block as Record<string, unknown>
      const blockType = String(rec['type'] ?? '').toLowerCase()

      if (TEXT_BLOCK_TYPES.has(blockType)) {
        const text = String(rec['text'] ?? '').trim()
        if (text) {
          textParts.push(text)
        }
        continue
      }
      if (SKIP_BLOCK_TYPES.has(blockType)) {
        continue
      }
      if (TOOL_USE_TYPES.has(blockType)) {
        const name = String(rec['name'] ?? '') || 'tool_use'
        toolEvents.push({
          summary: `${name} input=${summarizeValue(rec['input'])}`,
          timestamp,
        })
        continue
      }
      if (TOOL_RESULT_TYPES.has(blockType)) {
        const toolUseId = String(rec['tool_use_id'] ?? '') || 'tool_result'
        toolEvents.push({
          summary: `${toolUseId} output=${summarizeValue(rec['content'])}`,
          timestamp,
        })
      }
    }

    const text = joinParagraphs(textParts)
    if ((role === 'user' || role === 'assistant') && text) {
      messages.push({ role, text, timestamp })
    }
  }

  return {
    client: 'claude',
    session_id: sessionId,
    title,
    started_at: startedAt,
    cwd,
    branch,
    messages: deduplicateMessages(messages),
    tool_events: deduplicateToolEvents(toolEvents),
    source_path: filePath,
  }
}

// ---------------------------------------------------------------------------
// Gemini parser
// ---------------------------------------------------------------------------

export function parseGeminiTranscript(filePath: string): ParsedTranscript {
  const stem = basename(filePath, extname(filePath))
  let sessionId = stem
  const title = stem
  let startedAt = normalizeTimestamp(statSync(filePath).mtimeMs / 1000)
  let cwd = ''
  let branch = ''
  const messages: TranscriptMessage[] = []
  const toolEvents: TranscriptToolEvent[] = []

  let payload: unknown
  if (extname(filePath).toLowerCase() === '.jsonl') {
    payload = loadJsonl(filePath)
  } else {
    payload = JSON.parse(readFileSync(filePath, 'utf-8')) as unknown
  }

  const metaKeys: ReadonlySet<string> = new Set(['sessionId', 'chatId', 'cwd', 'branch', 'timestamp'])
  const firstMeta = findFirstMappingWithKeys(payload, metaKeys)
  if (firstMeta !== null) {
    sessionId = String(firstMeta['sessionId'] ?? '') || String(firstMeta['chatId'] ?? '') || String(firstMeta['id'] ?? '') || sessionId
    startedAt = earliestTimestamp(startedAt, firstMeta['timestamp'])
    cwd = String(firstMeta['cwd'] ?? '') || String(firstMeta['projectRoot'] ?? '') || cwd
    branch = String(firstMeta['branch'] ?? '') || branch
  }

  function visit(node: unknown): void {
    if (Array.isArray(node)) {
      for (const item of node) {
        visit(item)
      }
      return
    }
    if (node === null || typeof node !== 'object') {
      return
    }
    const rec = node as Record<string, unknown>

    sessionId = String(rec['sessionId'] ?? '') || String(rec['chatId'] ?? '') || String(rec['id'] ?? '') || sessionId
    startedAt = earliestTimestamp(startedAt, rec['timestamp'])
    cwd = String(rec['cwd'] ?? '') || String(rec['projectRoot'] ?? '') || cwd
    branch = String(rec['branch'] ?? '') || branch

    const role = String(rec['role'] ?? rec['author'] ?? rec['sender'] ?? '').toLowerCase()
    const timestamp = normalizeTimestamp(rec['timestamp'], startedAt)

    if (role === 'user' || role === 'assistant' || role === 'model') {
      const normalizedRole = role === 'model' ? 'assistant' : role
      const text = extractGeminiText(rec)
      if (text) {
        messages.push({ role: normalizedRole, text, timestamp })
      }
    }

    const toolName =
      getNested(rec, 'toolUse', 'name') ??
      rec['toolName'] ??
      rec['functionName'] ??
      rec['tool']
    if (toolName) {
      toolEvents.push({
        summary: `${String(toolName)} input=${summarizeValue(rec['args'] ?? rec['input'])}`,
        timestamp,
      })
    }

    for (const value of Object.values(rec)) {
      visit(value)
    }
  }

  visit(payload)

  return {
    client: 'gemini',
    session_id: sessionId,
    title,
    started_at: startedAt,
    cwd,
    branch,
    messages: deduplicateMessages(messages),
    tool_events: deduplicateToolEvents(toolEvents),
    source_path: filePath,
  }
}

/**
 * Recall — on-demand transcript sync + latest session lookup.
 * Port of scripts/recall-session.py
 */

import { existsSync, readFileSync } from 'node:fs'
import { resolve, join } from 'node:path'

import initSqlJs from 'sql.js'

import { slugify } from '../transcript/common.js'
import { defaultGlobalTranscriptRoot, discoverSourceFiles, transcriptMatchesRepo } from '../transcript/discover.js'
import { importTranscript, transcriptHasContent } from '../transcript/import.js'
import { parseTranscript } from '../transcript/parse.js'
import { toPosixPath } from '../utils/path.js'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface RecallResult {
  found: boolean
  project: string
  repo: string
  imported_count: number
  message?: string
  client?: string
  session_id?: string
  title?: string
  started_at?: string
  cwd?: string
  branch?: string
  message_count?: number
  tool_event_count?: number
  global_clean_path?: string
  clean_content?: string
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export async function recall(
  root: string,
  projectName: string,
  globalRootOverride: string,
  activationTime: string,
): Promise<RecallResult> {
  const resolvedRoot = resolve(root)
  const repoSlug = slugify(projectName.trim() || (resolvedRoot.split(/[/\\]/).pop() ?? ''), 'project')
  const globalRoot = globalRootOverride ? resolve(globalRootOverride) : defaultGlobalTranscriptRoot()
  const effectiveActivation = activationTime || nowIso()

  const imported = await syncCurrentProject(resolvedRoot, repoSlug, globalRoot)

  const session = await findLatestSession(globalRoot, resolvedRoot, repoSlug, effectiveActivation)

  if (session === null) {
    return {
      found: false,
      project: repoSlug,
      repo: toPosixPath(resolvedRoot),
      imported_count: imported,
      message: 'No previous session found for this project.',
    }
  }

  const cleanPath = String(session['global_clean_path'] ?? '')
  let cleanContent = ''
  if (cleanPath && existsSync(cleanPath)) {
    try {
      cleanContent = readFileSync(cleanPath, 'utf-8')
    } catch {
      // ignore read errors
    }
  }

  return {
    found: true,
    project: repoSlug,
    repo: toPosixPath(resolvedRoot),
    imported_count: imported,
    client: String(session['client'] ?? ''),
    session_id: String(session['session_id'] ?? ''),
    title: String(session['title'] ?? ''),
    started_at: String(session['started_at'] ?? ''),
    cwd: String(session['cwd'] ?? ''),
    branch: String(session['branch'] ?? ''),
    message_count: Number(session['message_count'] ?? 0),
    tool_event_count: Number(session['tool_event_count'] ?? 0),
    global_clean_path: cleanPath,
    clean_content: cleanContent,
  }
}

// ---------------------------------------------------------------------------
// Sync current project
// ---------------------------------------------------------------------------

export async function syncCurrentProject(root: string, repoSlug: string, globalRoot: string): Promise<number> {
  const discovered = discoverSourceFiles()
  let imported = 0

  for (const [client, source] of discovered) {
    let parsed
    try {
      parsed = parseTranscript(client, source)
    } catch {
      continue
    }

    if (!transcriptHasContent(parsed)) continue
    if (!transcriptMatchesRepo(parsed, root, repoSlug)) continue

    try {
      await importTranscript(parsed, root, globalRoot, repoSlug, 'not-set', true)
      imported++
    } catch {
      continue
    }
  }

  return imported
}

// ---------------------------------------------------------------------------
// Find latest session
// ---------------------------------------------------------------------------

export async function findLatestSession(
  globalRoot: string,
  root: string,
  repoSlug: string,
  activationTime: string,
): Promise<Record<string, unknown> | null> {
  const dbPath = join(globalRoot, 'index', 'search.sqlite')
  if (!existsSync(dbPath)) {
    return findLatestFromJsonl(globalRoot, root, repoSlug, activationTime)
  }

  try {
    const SQL = await initSqlJs()
    const db = new SQL.Database(readFileSync(dbPath))
    try {
      const stmt = db.prepare(
        'SELECT * FROM transcripts WHERE started_at < ? ORDER BY started_at DESC LIMIT 20',
      )
      stmt.bind([activationTime])

      const resolvedRoot = toPosixPath(resolve(root)).toLowerCase()
      const columns = stmt.getColumnNames()

      while (stmt.step()) {
        const values = stmt.get()
        const row: Record<string, unknown> = {}
        for (let i = 0; i < columns.length; i++) {
          row[columns[i]!] = values[i]
        }
        const cwd = String(row['cwd'] ?? '')
        const project = String(row['project'] ?? '')
        if (cwdMatches(cwd, resolvedRoot) || project === repoSlug) {
          stmt.free()
          return row
        }
      }
      stmt.free()
    } finally {
      db.close()
    }
  } catch {
    return findLatestFromJsonl(globalRoot, root, repoSlug, activationTime)
  }

  return null
}

// ---------------------------------------------------------------------------
// JSONL fallback
// ---------------------------------------------------------------------------

export function findLatestFromJsonl(
  globalRoot: string,
  root: string,
  repoSlug: string,
  activationTime: string,
): Record<string, unknown> | null {
  const jsonlPath = join(globalRoot, 'index', 'sessions.jsonl')
  if (!existsSync(jsonlPath)) return null

  const resolvedRoot = toPosixPath(resolve(root)).toLowerCase()
  const candidates: Record<string, unknown>[] = []

  let content: string
  try {
    content = readFileSync(jsonlPath, 'utf-8')
  } catch {
    return null
  }

  for (const line of content.split('\n')) {
    const trimmed = line.trim()
    if (!trimmed) continue
    let entry: Record<string, unknown>
    try {
      entry = JSON.parse(trimmed) as Record<string, unknown>
    } catch {
      continue
    }

    const started = String(entry['started_at'] ?? '')
    if (started >= activationTime) continue

    const cwd = String(entry['cwd'] ?? '')
    const project = String(entry['project'] ?? '')
    if (cwdMatches(cwd, resolvedRoot) || project === repoSlug) {
      candidates.push(entry)
    }
  }

  if (candidates.length === 0) return null

  candidates.sort((a, b) => {
    const aTime = String(a['started_at'] ?? '')
    const bTime = String(b['started_at'] ?? '')
    return bTime.localeCompare(aTime)
  })
  return candidates[0]!
}

// ---------------------------------------------------------------------------
// CWD matching
// ---------------------------------------------------------------------------

export function cwdMatches(cwd: string, resolvedRoot: string): boolean {
  if (!cwd) return false
  try {
    const cwdResolved = toPosixPath(resolve(cwd)).toLowerCase()
    if (cwdResolved === resolvedRoot) return true
    const prefix = resolvedRoot.endsWith('/') ? resolvedRoot : resolvedRoot + '/'
    return cwdResolved.startsWith(prefix)
  } catch {
    return false
  }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function nowIso(): string {
  return new Date().toISOString().replace(/\.\d{3}Z$/, 'Z')
}

export function formatText(payload: RecallResult): string {
  if (!payload.found) {
    return [
      `project: ${payload.project}`,
      `imported: ${payload.imported_count}`,
      `result: ${payload.message ?? 'No previous session found.'}`,
    ].join('\n')
  }

  const lines = [
    `project: ${payload.project}`,
    `client: ${payload.client ?? ''}`,
    `session_id: ${payload.session_id ?? ''}`,
    `title: ${payload.title ?? ''}`,
    `started_at: ${payload.started_at ?? ''}`,
    `cwd: ${payload.cwd ?? ''}`,
    `branch: ${payload.branch ?? ''}`,
    `messages: ${payload.message_count ?? 0}`,
    `tool_events: ${payload.tool_event_count ?? 0}`,
    `imported_this_sync: ${payload.imported_count}`,
    `clean_transcript: ${payload.global_clean_path ?? ''}`,
  ]

  if (payload.clean_content) {
    lines.push('', '--- clean transcript content ---', payload.clean_content)
  }

  return lines.join('\n')
}

