/**
 * Manage ~/.memorytree/alerts.json — append, dedup, threshold, display.
 * Port of scripts/_alert_utils.py
 */

import { existsSync, mkdirSync, readFileSync, unlinkSync, writeFileSync } from 'node:fs'
import { homedir } from 'node:os'
import { dirname, resolve } from 'node:path'

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

export const MAX_ALERTS = 100

export const ALERT_TYPES: ReadonlySet<string> = new Set([
  'no_remote',
  'sensitive_match',
  'push_failed',
  'lock_held',
])

export const FAILURE_THRESHOLD = 3

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface Alert {
  readonly timestamp: string
  readonly project: string
  readonly type: string
  readonly message: string
  readonly count: number
  readonly [key: string]: unknown
}

// ---------------------------------------------------------------------------
// Path helpers
// ---------------------------------------------------------------------------

export function alertsPath(): string {
  return resolve(homedir(), '.memorytree', 'alerts.json')
}

function failureStatePath(): string {
  return resolve(homedir(), '.memorytree', 'failure_counts.json')
}

// ---------------------------------------------------------------------------
// Timestamp helper (self-contained — no cross-module dependency)
// ---------------------------------------------------------------------------

function utcTimestamp(): string {
  return new Date().toISOString().replace(/\.\d{3}Z$/, 'Z')
}

// ---------------------------------------------------------------------------
// Read / Write alerts
// ---------------------------------------------------------------------------

export function readAlerts(): readonly Alert[] {
  const path = alertsPath()
  if (!existsSync(path)) {
    return []
  }
  try {
    const text = readFileSync(path, 'utf-8')
    const data: unknown = JSON.parse(text)
    if (!Array.isArray(data)) {
      return []
    }
    return data as Alert[]
  } catch {
    return []
  }
}

export function writeAlert(project: string, alertType: string, message: string): void {
  const alerts = readAlerts()
  const now = utcTimestamp()

  let found = false
  const updated: Alert[] = []

  for (const alert of alerts) {
    if (alert.project === project && alert.type === alertType) {
      updated.push({
        ...alert,
        timestamp: now,
        message,
        count: (alert.count ?? 1) + 1,
      })
      found = true
    } else {
      updated.push({ ...alert })
    }
  }

  if (!found) {
    updated.push({ timestamp: now, project, type: alertType, message, count: 1 })
  }

  const trimmed = updated.length > MAX_ALERTS
    ? updated.slice(updated.length - MAX_ALERTS)
    : updated

  saveAlerts(trimmed)
}

// ---------------------------------------------------------------------------
// Threshold-based writes
// ---------------------------------------------------------------------------

export function writeAlertWithThreshold(
  project: string,
  alertType: string,
  message: string,
): void {
  const counts = readFailureCounts()
  const key = `${project}::${alertType}`
  const current = ((counts[key] as number | undefined) ?? 0) + 1
  const newCounts: Record<string, number> = { ...counts, [key]: current }
  saveFailureCounts(newCounts)

  if (current >= FAILURE_THRESHOLD) {
    writeAlert(project, alertType, message)
  }
}

export function resetFailureCount(project: string, alertType: string): void {
  const counts = readFailureCounts()
  const key = `${project}::${alertType}`
  if (key in counts) {
    const newCounts: Record<string, number> = {}
    for (const [k, v] of Object.entries(counts)) {
      if (k !== key) {
        newCounts[k] = v
      }
    }
    saveFailureCounts(newCounts)
  }
}

// ---------------------------------------------------------------------------
// Clear
// ---------------------------------------------------------------------------

export function clearAlerts(): void {
  const path = alertsPath()
  if (existsSync(path)) {
    try {
      unlinkSync(path)
    } catch {
      // Silently ignore removal errors (matches Python behaviour)
    }
  }
}

// ---------------------------------------------------------------------------
// Display
// ---------------------------------------------------------------------------

export function formatAlertsForDisplay(alerts: readonly Record<string, unknown>[]): string {
  if (alerts.length === 0) {
    return ''
  }
  const lines: string[] = []
  for (const alert of alerts) {
    const count = typeof alert['count'] === 'number' ? alert['count'] : 1
    const countSuffix = count > 1 ? ` (x${String(count)})` : ''
    const type = typeof alert['type'] === 'string' ? alert['type'] : 'unknown'
    const project = typeof alert['project'] === 'string' ? alert['project'] : '?'
    const message = typeof alert['message'] === 'string' ? alert['message'] : ''
    lines.push(`  [${type}] ${project}: ${message}${countSuffix}`)
  }
  return lines.join('\n')
}

// ---------------------------------------------------------------------------
// Internal — alerts persistence
// ---------------------------------------------------------------------------

function saveAlerts(alerts: readonly Alert[]): void {
  const path = alertsPath()
  mkdirSync(dirname(path), { recursive: true })
  writeFileSync(path, JSON.stringify(alerts, null, 2) + '\n', 'utf-8')
}

// ---------------------------------------------------------------------------
// Internal — failure counts persistence
// ---------------------------------------------------------------------------

function readFailureCounts(): Record<string, number> {
  const path = failureStatePath()
  if (!existsSync(path)) {
    return {}
  }
  try {
    const text = readFileSync(path, 'utf-8')
    const data: unknown = JSON.parse(text)
    if (data === null || typeof data !== 'object' || Array.isArray(data)) {
      return {}
    }
    return data as Record<string, number>
  } catch {
    return {}
  }
}

function saveFailureCounts(counts: Record<string, number>): void {
  const path = failureStatePath()
  mkdirSync(dirname(path), { recursive: true })
  writeFileSync(path, JSON.stringify(counts, null, 2) + '\n', 'utf-8')
}

/**
 * Transcript discovery — file scanning and project matching.
 * Port of scripts/_transcript_discover.py
 */

import { existsSync, statSync } from 'node:fs'
import { homedir } from 'node:os'
import { basename, dirname, resolve } from 'node:path'

import fg from 'fast-glob'

import type { ParsedTranscript } from '../types/transcript.js'
import { slugify, CLIENTS } from './common.js'
import { toPosixPath } from '../utils/path.js'

// ---------------------------------------------------------------------------
// Glob patterns per client
// ---------------------------------------------------------------------------

const CLIENT_PATTERNS: Readonly<Record<string, readonly string[]>> = {
  codex: ['sessions/**/*.jsonl'],
  claude: ['projects/**/*.jsonl'],
  gemini: [
    'tmp/*/checkpoints/**/*.json',
    'tmp/*/checkpoints/**/*.jsonl',
    'history/**/*.json',
    'history/**/*.jsonl',
    'chats/**/*.json',
    'chats/**/*.jsonl',
  ],
}

// ---------------------------------------------------------------------------
// Defaults
// ---------------------------------------------------------------------------

export function defaultGlobalTranscriptRoot(): string {
  return toPosixPath(resolve(homedir(), '.memorytree', 'transcripts'))
}

export function defaultClientRoots(): Record<string, string> {
  const home = homedir()
  return {
    codex: resolve(home, '.codex'),
    claude: resolve(home, '.claude'),
    gemini: resolve(home, '.gemini'),
  }
}

// ---------------------------------------------------------------------------
// File discovery
// ---------------------------------------------------------------------------

export function discoverSourceFiles(
  clients?: ReadonlySet<string>,
  roots?: Readonly<Record<string, string>>,
): Array<[string, string]> {
  const requested = clients ?? CLIENTS
  const resolvedRoots = roots ?? defaultClientRoots()
  const matches: Array<[string, string]> = []
  const seen = new Set<string>()

  for (const client of [...requested].sort()) {
    const root: string | undefined = resolvedRoots[client]
    if (root === undefined || !existsSync(root)) continue

    const patterns = CLIENT_PATTERNS[client]
    if (patterns === undefined) continue

    for (const pattern of patterns) {
      const paths = fg.sync(pattern, { cwd: root, absolute: true, onlyFiles: true })
      for (const filePath of paths) {
        const resolved = toPosixPath(resolve(filePath))
        const key = resolved.toLowerCase()
        if (seen.has(key)) continue
        seen.add(key)
        matches.push([client, resolved])
      }
    }
  }

  matches.sort((a, b) => {
    const mtimeA = safeFileMtime(a[1])
    const mtimeB = safeFileMtime(b[1])
    if (mtimeB !== mtimeA) return mtimeB - mtimeA
    const pathA = a[1].toLowerCase()
    const pathB = b[1].toLowerCase()
    // Reverse sort: higher path string comes first (matching Python's reverse=True)
    if (pathB > pathA) return 1
    if (pathB < pathA) return -1
    return 0
  })

  return matches
}

// ---------------------------------------------------------------------------
// Project slug inference
// ---------------------------------------------------------------------------

export function inferProjectSlug(parsed: ParsedTranscript): string {
  if (parsed.cwd) {
    try {
      const cwdBase = basename(parsed.cwd)
      return slugify(cwdBase, 'project')
    } catch {
      // fall through
    }
  }

  if (parsed.client === 'claude') {
    let parentName = basename(dirname(parsed.source_path)).toLowerCase()
    parentName = parentName.replace(/^[a-z]--/, '')
    return slugify(parentName, 'project')
  }

  if (parsed.client === 'gemini') {
    const parentDir = basename(dirname(parsed.source_path))
    if (parentDir) {
      return slugify(parentDir, 'project')
    }
  }

  return 'unknown-project'
}

// ---------------------------------------------------------------------------
// Repo matching
// ---------------------------------------------------------------------------

export function transcriptMatchesRepo(
  parsed: ParsedTranscript,
  repoRoot: string,
  repoSlug: string,
): boolean {
  const normalizedRepo = toPosixPath(resolve(repoRoot)).toLowerCase()

  if (parsed.cwd) {
    try {
      const normalizedCwd = toPosixPath(resolve(parsed.cwd)).toLowerCase()
      if (normalizedCwd === normalizedRepo) return true
      // Check if repoRoot is a parent of cwd
      const repoPrefix = normalizedRepo.endsWith('/')
        ? normalizedRepo
        : normalizedRepo + '/'
      if (normalizedCwd.startsWith(repoPrefix)) return true
    } catch {
      // fall through
    }
  }

  return projectSlugsMatch(inferProjectSlug(parsed), repoSlug)
}

// ---------------------------------------------------------------------------
// Slug matching
// ---------------------------------------------------------------------------

export function projectSlugsMatch(left: string, right: string): boolean {
  return Boolean(
    left && right && left === right && left !== 'unknown-project',
  )
}

// ---------------------------------------------------------------------------
// Safe mtime
// ---------------------------------------------------------------------------

export function safeFileMtime(filePath: string): number {
  try {
    return statSync(filePath).mtimeMs / 1000
  } catch {
    return 0
  }
}

/**
 * Logging setup for heartbeat — file output + stderr.
 * Port of scripts/_log_utils.py
 */

import { appendFileSync, mkdirSync } from 'node:fs'
import { homedir } from 'node:os'
import { resolve } from 'node:path'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type LogLevel = 'debug' | 'info' | 'warn' | 'error'

export interface Logger {
  debug(msg: string): void
  info(msg: string): void
  warn(msg: string): void
  error(msg: string): void
  exception(msg: string, err?: unknown): void
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const LEVEL_PRIORITY: Readonly<Record<LogLevel, number>> = {
  debug: 0,
  info: 1,
  warn: 2,
  error: 3,
}

const LEVEL_LABELS: Readonly<Record<LogLevel, string>> = {
  debug: 'DEBUG',
  info: 'INFO',
  warn: 'WARN',
  error: 'ERROR',
}

// ---------------------------------------------------------------------------
// Singleton
// ---------------------------------------------------------------------------

let singleton: MemoryTreeLogger | undefined

// ---------------------------------------------------------------------------
// MemoryTreeLogger
// ---------------------------------------------------------------------------

class MemoryTreeLogger implements Logger {
  private readonly levelPriority: number
  private readonly logFilePath: string | undefined

  constructor(logLevel: LogLevel) {
    this.levelPriority = LEVEL_PRIORITY[logLevel]

    const filePath = logFilePathForToday()
    const logDir = resolve(filePath, '..')
    try {
      mkdirSync(logDir, { recursive: true })
      // Verify we can write by doing nothing — the first real append will
      // confirm access.  We store the path only after the dir exists.
      this.logFilePath = filePath
    } catch {
      // Cannot create log directory — stderr-only mode.
      this.writeStderr('WARN', `Could not open log file: ${filePath}`)
      this.logFilePath = undefined
    }
  }

  debug(msg: string): void {
    this.log('debug', msg)
  }

  info(msg: string): void {
    this.log('info', msg)
  }

  warn(msg: string): void {
    this.log('warn', msg)
  }

  error(msg: string): void {
    this.log('error', msg)
  }

  exception(msg: string, err?: unknown): void {
    if (err instanceof Error && err.stack) {
      this.log('error', `${msg}\n${err.stack}`)
    } else if (err !== undefined) {
      this.log('error', `${msg}\n${String(err)}`)
    } else {
      this.log('error', msg)
    }
  }

  // -----------------------------------------------------------------------
  // Internal
  // -----------------------------------------------------------------------

  private log(level: LogLevel, msg: string): void {
    if (LEVEL_PRIORITY[level] < this.levelPriority) {
      return
    }

    const label = LEVEL_LABELS[level]
    const formatted = `${timestamp()} [${label}] ${msg}`

    this.writeStderr(label, msg)
    this.writeFile(formatted)
  }

  private writeStderr(_label: string, _msg: string): void {
    // Use the pre-formatted line for consistency.  We rebuild here so the
    // standalone warning in the constructor can also call this without a
    // full formatted line.
    const line = `${timestamp()} [${_label}] ${_msg}\n`
    process.stderr.write(line)
  }

  private writeFile(formatted: string): void {
    if (this.logFilePath === undefined) {
      return
    }
    try {
      appendFileSync(this.logFilePath, formatted + '\n', 'utf-8')
    } catch {
      // Silently ignore file-write errors — stderr is the primary channel.
    }
  }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Create (or return existing) singleton logger.
 *
 * The `logLevel` parameter is only used on the *first* call.  Subsequent
 * calls return the existing logger regardless of the level argument.
 */
export function setupLogging(logLevel: LogLevel = 'info'): Logger {
  if (singleton !== undefined) {
    return singleton
  }
  singleton = new MemoryTreeLogger(resolveLevel(logLevel))
  return singleton
}

/**
 * Return the singleton logger.  If `setupLogging` has not been called yet
 * the logger is auto-created with default settings (`info` level).
 */
export function getLogger(): Logger {
  if (singleton === undefined) {
    singleton = new MemoryTreeLogger(resolveLevel('info'))
  }
  return singleton
}

/**
 * Reset the singleton — primarily useful for tests.
 */
export function _resetLogger(): void {
  singleton = undefined
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function resolveLevel(level: string): LogLevel {
  const lower = level.toLowerCase()
  const mapping: Record<string, LogLevel> = {
    debug: 'debug',
    info: 'info',
    warn: 'warn',
    warning: 'warn',
    error: 'error',
  }
  return mapping[lower] ?? 'info'
}

function logFilePathForToday(): string {
  const today = new Date().toISOString().slice(0, 10) // YYYY-MM-DD in UTC
  return resolve(homedir(), '.memorytree', 'logs', `heartbeat-${today}.log`)
}

function timestamp(): string {
  // Produce YYYY-MM-DDTHH:MM:SS in UTC matching the Python datefmt.
  const now = new Date()
  const y = now.getUTCFullYear()
  const mo = String(now.getUTCMonth() + 1).padStart(2, '0')
  const d = String(now.getUTCDate()).padStart(2, '0')
  const h = String(now.getUTCHours()).padStart(2, '0')
  const mi = String(now.getUTCMinutes()).padStart(2, '0')
  const s = String(now.getUTCSeconds()).padStart(2, '0')
  return `${y}-${mo}-${d}T${h}:${mi}:${s}`
}

